static bool IsAllowedScheme(string scheme)
{
    return scheme.Equals("http", StringComparison.OrdinalIgnoreCase) || 
           scheme.Equals("https", StringComparison.OrdinalIgnoreCase);
}

static bool IsBlockedHost(string host)
{
    var blockedHosts = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
    {
        "localhost",
        "127.0.0.1",
        "0.0.0.0",
        "::1",
        "169.254.169.254",
        "metadata.google.internal"
    };

    if (blockedHosts.Contains(host))
    {
        return true;
    }

    if (host.EndsWith(".local", StringComparison.OrdinalIgnoreCase) ||
        host.EndsWith(".localhost", StringComparison.OrdinalIgnoreCase) ||
        host.EndsWith(".internal", StringComparison.OrdinalIgnoreCase))
    {
        return true;
    }

    return false;
}

static bool IsBlockedIpAddress(IPAddress address)
{
    var bytes = address.GetAddressBytes();

    if (address.AddressFamily == AddressFamily.InterNetwork)
    {
        if (bytes[0] == 10) return true;
        if (bytes[0] == 127) return true;
        if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31) return true;
        if (bytes[0] == 192 && bytes[1] == 168) return true;
        if (bytes[0] == 169 && bytes[1] == 254) return true;
        if (bytes[0] == 0) return true;
        if (bytes[0] >= 224) return true;
    }
    else if (address.AddressFamily == AddressFamily.InterNetworkV6)
    {
        if (IPAddress.IsLoopback(address)) return true;
        if (address.IsIPv6LinkLocal) return true;
        if (address.IsIPv6SiteLocal) return true;
        if (address.IsIPv6Multicast) return true;
        
        if (bytes[0] == 0xfc || bytes[0] == 0xfd) return true;
        
        if (bytes.Take(16).All(b => b == 0)) return true;
    }

    return false;
}

static bool IsAllowedPort(int port)
{
    var blockedPorts = new HashSet<int>
    {
        22, 23, 25, 110, 143, 445, 3306, 3389, 5432, 5984, 6379, 8080, 9200, 27017
    };

    if (port == -1)
    {
        return true;
    }

    if (port < 1 || port > 65535)
    {
        return false;
    }

    return !blockedPorts.Contains(port);
}

static bool IsRestrictedHeader(string headerName)
{
    var restricted = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
    {
        "Host",
        "Connection",
        "Transfer-Encoding",
        "Upgrade"
    };

    return restricted.Contains(headerName);
